#include <stdio.h>
#include <string.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    char dummy[2];
    fgets(dummy, sizeof dummy, stdin); // consume newline after T
    const char *initial = "Global Bank";
    const char *updated = "World Trust Bank";
    for(int tc=0; tc<T; ++tc){
        char name1[101], name2[101];
        fgets(name1, sizeof name1, stdin);
        fgets(name2, sizeof name2, stdin);
        name1[strcspn(name1,"\n")] = '\0';
        name2[strcspn(name2,"\n")] = '\0';
        printf("Initial Bank Details:\n");
        printf("Bank: %s, Holder: %s\n", initial, name1);
        printf("Bank: %s, Holder: %s\n", initial, name2);
        printf("Updated Bank Details after rebranding:\n");
        printf("Bank: %s, Holder: %s\n", updated, name1);
        printf("Bank: %s, Holder: %s\n", updated, name2);
        if(tc!=T-1) printf("\n");
    }
    return 0;
}

