code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static class Bank {
        static String bankName = "Global Bank";
        String holder;
        Bank(String h){ holder = h; }
        void display(PrintWriter out){
            out.println("Bank: " + bankName + ", Holder: " + holder);
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        for(int tc=0; tc<T; ++tc){
            String name1 = br.readLine();
            String name2 = br.readLine();
            Bank acc1 = new Bank(name1);
            Bank acc2 = new Bank(name2);
            out.println("Initial Bank Details:");
            acc1.display(out);
            acc2.display(out);
            Bank.bankName = "World Trust Bank";
            out.println("Updated Bank Details after rebranding:");
            acc1.display(out);
            acc2.display(out);
            if(tc!=T-1) out.println();
        }
        out.flush();
    }
}

